    vector<long long> ans;
    for (auto& q : queries) {
        long long l = q[0], r = q[1], threshold = q[2];
        unordered_map<long long, int> freq;
        for (int i = l; i <= r; ++i) {
            freq[nums[i]]++;
        }
        long long max_freq = -1;
        long long best = -1;
        for (auto& [x, cnt] : freq) {
            if (cnt >= threshold) {
                if (cnt > max_freq) {
                    max_freq = cnt;
                    best = x;
                } else if (cnt == max_freq) {
                    if (x < best) {
