import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        List<Long> ans = new ArrayList<>();
        for (long[] q : queries) {
            long l = q[0], r = q[1], threshold = q[2];
            HashMap<Long, Integer> freq = new HashMap<>();
            for (int i = (int) l; i <= r; i++) {
                long num = nums[i];
                freq.put(num, freq.getOrDefault(num, 0) + 1);
            }
            long maxFreq = -1;
            long best = -1;
            for (Map.Entry<Long, Integer> entry : freq.entrySet()) {
                long num = entry.getKey();
                int cnt = entry.getValue();
                if (cnt >= threshold) {
                    if (cnt > maxFreq) {
                        maxFreq = cnt;
                        best = num;
                    } else if (cnt == maxFreq) {
                        if (num < best) {
                            best = num;
                        }
                    }
                }
            }
            ans.add(best == -1 ? -1 : best);
        }
        long[] result = new long[ans.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = ans.get(i);
        }
        return result;
    }
}
